const rows = [];

for (const cat of c) {
  for (const item of cat.data) {
    const [name, price, comparePrice, brand, features] = item;
    const poolKey = cat.id === 'dc2adcc5-aae2-4b35-b4ca-47aa71a41005' ? 'electronics' :
                     cat.id === 'dab25f33-5cf1-49dd-8330-aeeb23ccf4d2' ? 'beauty' :
                     cat.id === 'dd57f794-38cb-4692-bf99-d6791f3e3f58' ? 'books' :
                     cat.id === '40a5e9b9-17a2-486f-b8ab-b2923da76f59' ? 'fashion' :
                     cat.id === 'd5bd9a10-3261-4475-ad3d-191fb9a92967' ? 'home' : 'sports';
    const imgs = gimgs(unsplash[poolKey]);
    const imgUrls = imgs.map(u => sq(u)).join(',');
    const featStr = features.map(f => sq(f)).join(',');

    const descPool = descs[cat.id];
    const description = descPool[ri(0, descPool.length - 1)](name);

    const countInStock = ri(10, 200);
    const rating = rd(3.0, 5.0, 1);
    const numReviews = ri(0, 500);
    const isFeatured = rb(0.2);

    rows.push(`(gen_random_uuid(),${sq(name)},${sq(description)},${price},${comparePrice ?? 'NULL'},ARRAY[${imgUrls}]::text[],${sq(cat.id)},${sq(brand)},${countInStock},${rating},${numReviews},ARRAY[${featStr}]::text[],${isFeatured ? 'true' : 'false'},NOW(),NOW())`);
  }
}

let sql = `INSERT INTO public.products (id, name, description, price, compare_price, images, category_id, brand, count_in_stock, rating, num_reviews, features, is_featured, created_at, updated_at)
VALUES\n`;
sql += rows.join(',\n') + ';\n';

fs.writeFileSync('seed_products.sql', sql);

const stats = fs.statSync('seed_products.sql');
const lines = sql.split('\n').length;
const insertRows = sql.match(/gen_random_uuid/g)?.length ?? 0;

